# Pagination

## Import

```jsx live=false
import { Pagination } from '@node-real/bee';
```

## Usage

```jsx
function Example() {
  const [page, setPage] = useState(1);

  const onChangePage = (page) => {
    setPage(page);
  };

  return <Pagination current={page} total={20} onChange={onChangePage} />;
}
```

## Status

```jsx
<VStack align="flex-start" spacing={24}>
  <Pagination current={1} total={10} isDisabled />
  <Pagination current={20} total={20} />
</VStack>
```

## Large pages

```jsx
function Example() {
  const [page, setPage] = useState(10000000);

  const onChangePage = (page) => {
    setPage(page);
  };

  return (
    <VStack align="flex-start" spacing={24}>
      <Pagination current={1} total={10000000000000} isDisabled />
      <Pagination current={page} total={10000000000000} onChange={onChangePage} />
    </VStack>
  );
}
```

